var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"너희 둘. 또 짱박혀서 농땡이 부리면 독방행이라고 경고했을 텐데?","JPN":"そこの二人。またサボったら一人部屋に閉じ込めると警告したよな？","ENG":"You two. I warned you that you'll end up in solitary if you keep slacking off.","TWN":"你們二個，再給我混水摸魚，就把你們關到禁閉室！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐, 어쩌죠? 무기도 있으니, 다 터트리고 튈까요?","JPN":"ソーニャ、どうしましょう？　武器もあるから全部爆発させて逃げますか？","ENG":"What should we do, Sonya? We got our weapons, so should we just blow everything up and make a run for it?","TWN":"索妮雅，怎麼辦？反正我們有武器，不如就炸掉這裡逃獄吧？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그건 위험해. 격벽의 방위는 소홀할지 몰라도, 탈옥 루트는 전부 철저하게 막아뒀어.","JPN":"それは危ない。隔壁の防衛は手薄でも、脱獄ルートは全部徹底に封鎖してあるんだ。","ENG":"That's too risky. The ocean wall may have light security, but the security for prisoner escape routes is airtight.","TWN":"這麼做有風險， 隔離牆的看守或許不嚴，但逃獄路線完全被堵得死死的。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"내가 대화해 볼 테니 신호 보내기 전까진 무기 잘 숨겨.","JPN":"あたしが話してみるから合図する前までは武器をちゃんと隠して。","ENG":"I'll talk to them and give you a sign, so hide your weapon in the meantime.","TWN":"我來跟她說說看，你先把武器藏好，等我跟你打PASS。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"미안- 사람들 비명소리가 들리길래 잠깐 와서 도와준 거야.","JPN":"悪いー人々の悲鳴が聞こえたから、ちょっと助けに来ただけだ。","ENG":"Sorry. I heard people scream, so I just stopped by to help.","TWN":"抱歉，我們聽到有人在尖叫，所以才跑過來幫忙。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"음? 무슨 소란인가 했더니, 침식체 몇 마리가 기어올라왔었군.","JPN":"うん？　何の騒ぎかと思ったら侵食体が何体か登ってきたのか。","ENG":"Hmm? I was wondering what all the ruckus was about. I guess a few C.O.s crawled up.","TWN":"是嗎？我還想說在吵什麼，原來是出現幾隻侵蝕體嗎？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"너희들끼리 이 많은 것들을 해치운 건가? 무기도 없이?","JPN":"お前たちでこの数を全部倒したのか？　武器もなく？","ENG":"Did you all take care of these yourselves? Without any weapons?","TWN":"這些都你們自己處理掉的嗎？沒有使用武器？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아하하- 이래봬도 카운터라서…","JPN":"あははー　これでもカウンターだから……","ENG":"Ah ha ha. Well, I technically am a Counter...","TWN":"哈哈哈，別看我們年紀小，好歹也是制裁者的嘛…"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"잠깐. 어디서 화약냄새가 나는 것 같은데?","JPN":"ちょっと。どこかで火薬の匂いがするが？","ENG":"Wait. I think I smell gunpowder.","TWN":"等等，我好像有聞到火藥的味道？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"윽…….","JPN":"うっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"거기 너! 지금 어디로 가는 거지?","JPN":"そこのお前！　今どこに行くんだ！","ENG":"You there! Where do you think you're going?!","TWN":"你！你要去哪裡？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저, 저는… 긴장을 좀 했더니 속이 안 좋아서요.","JPN":"わ、私は……緊張したら少しお腹が痛くなりまして。","ENG":"I-I was too nervous... and I don't feel well.","TWN":"我…我剛太緊張，身體有點不舒服。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"너, 이리 와서 손 좀 내밀어 봐.","JPN":"お前、こっち来て手を出してみろ。","ENG":"You. Come here and show your hands.","TWN":"你過來，把手伸出來。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐…! 역시 터트리는 편이…!","JPN":"ソーニャ……！　やっぱり爆発させた方が……！","ENG":"Sonya, maybe we really should blow everything up...!","TWN":"索妮雅…！還是轟掉比較…！"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저기-","JPN":"あのさー","ENG":"Hey.","TWN":"長官。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우릴 근무지 이탈로 처벌해봐야, 관리 미흡으로 담당자인 당신만 귀찮아질 뿐이지 않아?","JPN":"あたしたちを勤務地離脱で処罰しても、管理不足であなたが面倒くさくなるだけだよね？","ENG":"If you punish us for leaving the designated work area, it would only make you look bad for failing to watch us.","TWN":"我們擅自離開工作區域是應該受到懲罰沒錯，但要是被上面的人知道，恐怕也會怪你管理不善，這樣反而會造成你的麻煩吧？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"무슨 소릴 하고 싶은 거지?","JPN":"何が言いたい？","ENG":"What are you trying to say?","TWN":"你想說什麼？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"내 말은- 우린 얌전히 돌아갈 테니 한 번만 못 본 셈 쳐달란 거야.","JPN":"だからーあたしたちは大人しく戻るから一回だけ見逃してくれってこと。","ENG":"I'm saying that you should leave us be and forget about us. We're going to quietly step back.","TWN":"我的意思是，我們會乖乖回去，這次就放我們一馬吧。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"침식체는 당신들이 전부 처리했다고 보고하면 그쪽 실적에도 도움이 될 테고… 안 그래?","JPN":"侵食体は全部あなたが処理したって報告すれば実績も上がるから……いいよね？","ENG":"Plus, you'll be given extra credit if you claim you handled all the C.O.s yourself... Right?","TWN":"你可以邀功說這些侵蝕體都是你一人處理掉的，這樣你的績效也會加分吧…你說對嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"WORKER_FRONTBAY_NULL_WATCH","text":{"KOREA":"지금 움직이면 경비들 의심을 살 테니, 내일 노동시간 전까지 알아서 복귀해.","JPN":"今動くと警備に怪しまれるから、明日の労働時間前までに勝手に復帰しろ。","ENG":"The guards might find it suspicious if you move now. So get back before tomorrow's work hours on your own.","TWN":"現在移動會引起守衛的懷疑，明天勞動時間前自己回來。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"WORKER_FRONTBAY_NULL_WATCH","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};